/**
 * Helper class for Priority Queue (Min Heap)
 * Stores elements as [distance, index]
 */
class PriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) {
        return Math.floor((i - 1) / 2);
    }

    getLeftChildIndex(i) {
        return 2 * i + 1;
    }

    getRightChildIndex(i) {
        return 2 * i + 2;
    }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    compare(a, b) {
        // Compare based on distance (first element)
        return a[0] - b[0];
    }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(i) {
        let parentIndex = this.getParentIndex(i);
        while (i > 0 && this.compare(this.heap[i], this.heap[parentIndex]) < 0) {
            this.swap(i, parentIndex);
            i = parentIndex;
            parentIndex = this.getParentIndex(i);
        }
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    bubbleDown(i) {
        let minIndex = i;
        const size = this.heap.length;

        while (true) {
            const left = this.getLeftChildIndex(i);
            const right = this.getRightChildIndex(i);

            // Check left child
            if (left < size && this.compare(this.heap[left], this.heap[minIndex]) < 0) {
                minIndex = left;
            }

            // Check right child
            if (right < size && this.compare(this.heap[right], this.heap[minIndex]) < 0) {
                minIndex = right;
            }

            if (minIndex !== i) {
                this.swap(i, minIndex);
                i = minIndex;
            } else {
                break;
            }
        }
    }
}


function solve(nums, queries) {
    const N = nums.length;

    // 1. Precalculate closest(x)
    const closest = new Array(N);
    for (let x = 0; x < N; x++) {
        let minDiff = Infinity;
        let closestY = -1;

        // Check neighbors
        const neighbors = [];
        if (x > 0) neighbors.push(x - 1);
        if (x < N - 1) neighbors.push(x + 1);

        for (const y of neighbors) {
            const diff = Math.abs(nums[x] - nums[y]);
            if (diff < minDiff) {
                minDiff = diff;
                closestY = y;
            } else if (diff === minDiff) {
                // Tie breaker: choose smaller index
                closestY = Math.min(closestY, y);
            }
        }
        closest[x] = closestY;
    }

    const results = [];

    // 2. Process each query using Dijkstra's algorithm
    for (const query of queries) {
        let L = query[0];
        let R = query[1];

        // Dijkstra initialization
        const dist = new Array(N).fill(Infinity);
        const pq = new PriorityQueue();

        dist[L] = 0;
        pq.enqueue([0, L]);

        let minCost = Infinity;

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            if (u === R) {
                minCost = d;
                break; 
            }

            // --- Relaxation Step ---

            // Rule 2: Move to closest(u), cost 1
            const v_closest = closest[u];
            const cost_r2 = 1;
            if (dist[u] + cost_r2 < dist[v_closest]) {
                dist[v_closest] = dist[u] + cost_r2;
                pq.enqueue([dist[v_closest], v_closest]);
            }

            // Rule 1: Move to any other node v, cost |nums[u] - nums[v]|
            // NOTE: This loop makes the complexity O(N^2) per query, 
            // which is too slow for N=10^5, but is the direct implementation of the rules.
            for (let v = 0; v < N; v++) {
                if (u === v) continue;

                const cost_r1 = Math.abs(nums[u] - nums[v]);

                if (dist[u] + cost_r1 < dist[v]) {
                    dist[v] = dist[u] + cost_r1;
                    pq.enqueue([dist[v], v]);
                }
            }
        }

        results.push(minCost);
    }

    return results;
}

